import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => ''),
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { preCompactGuard } from '../../lifecycle/pre-compact-guard.js';
import { existsSync, readFileSync } from 'node:fs';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

function makeInput(): HookInput {
  return { tool_name: 'PreCompact', session_id: 'test', tool_input: {} };
}

let testCtx: ReturnType<typeof createTestContext>;

describe('preCompactGuard', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.clearAllMocks();
    delete process.env.CLAUDE_CODE_ALLOW_COMPACT_DURING_AGENTS;
  });

  it('allows compaction when no agents are active', () => {
    vi.mocked(existsSync).mockReturnValue(false);
    const result = preCompactGuard(makeInput(), testCtx);
    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('allows compaction when all agents are stale (>5min)', () => {
    const tenMinAgo = new Date(Date.now() - 10 * 60 * 1000).toISOString();
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ timestamp: tenMinAgo, subagent_type: 'test-generator' })
    );
    const result = preCompactGuard(makeInput(), testCtx);
    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('blocks compaction when background agents are active', () => {
    const twoMinAgo = new Date(Date.now() - 2 * 60 * 1000).toISOString();
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ timestamp: twoMinAgo, subagent_type: 'workflow-architect' })
    );
    const result = preCompactGuard(makeInput(), testCtx);
    expect(result.continue).toBe(false);
    expect(result.decision).toBe('block');
    expect(result.stopReason).toContain('workflow-architect');
  });

  it('allows when env override set', () => {
    const twoMinAgo = new Date(Date.now() - 2 * 60 * 1000).toISOString();
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue(
      JSON.stringify({ timestamp: twoMinAgo, subagent_type: 'test-generator' })
    );
    process.env.CLAUDE_CODE_ALLOW_COMPACT_DURING_AGENTS = '1';
    const result = preCompactGuard(makeInput(), testCtx);
    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('handles corrupt spawn log gracefully', () => {
    vi.mocked(existsSync).mockReturnValue(true);
    vi.mocked(readFileSync).mockReturnValue('not valid json');
    const result = preCompactGuard(makeInput(), testCtx);
    expect(result.continue).toBe(true);
  });
});
